import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { dotnetApi } from '../api/axios';
import { ENDPOINTS, NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import './Marketplace.css';

const Marketplace = () => {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    const loadMarketplace = async () => {
      setLoading(true);
      try {
        const response = await dotnetApi.get(ENDPOINTS.GET_MARKETPLACE, { params: { skip: 0, limit: 50 } });
        setItems(response.data?.data || response.data || []);
      } catch (error) {
        toast.error('Failed to load marketplace');
      }
      setLoading(false);
    };
    loadMarketplace();
  }, []);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  return (
    <div className="marketplace-page">
      <div className="marketplace-header">
        <button className="marketplace-back" onClick={() => navigate(-1)}>←</button>
        <h1 className="marketplace-title">Marketplace</h1>
      </div>

      {loading && <div className="groups-loading"><div className="page-loading-spinner" /></div>}

      {!loading && items.length === 0 && (
        <div className="groups-empty"><p>No marketplace items</p></div>
      )}

      {/* Item grid */}
      <div className="marketplace-grid">
        {items.map((item, index) => {
          const imgUrl = getImageUrl(item?.ad_img?.[0] || item?.ad_img?.[1]);
          return (
            <div
              key={item._id || index}
              className="marketplace-card"
              onClick={() => setSelectedItem(item)}
            >
              <div className="marketplace-card-img-wrap">
                {imgUrl ? (
                  <img src={imgUrl} alt="" className="marketplace-card-img" />
                ) : (
                  <div className="marketplace-card-img-placeholder">🎬</div>
                )}
              </div>
              <div className="marketplace-card-info">
                <span className="marketplace-card-title">{item.ad_title || 'Item'}</span>
                {item.amount && <span className="marketplace-card-price">{item.amount}</span>}
              </div>
            </div>
          );
        })}
      </div>

      {/* Detail modal */}
      {selectedItem && (
        <div className="marketplace-detail-overlay" onClick={() => setSelectedItem(null)}>
          <div className="marketplace-detail-card" onClick={(e) => e.stopPropagation()}>
            <button className="marketplace-detail-close" onClick={() => setSelectedItem(null)}>✕</button>

            {/* Images */}
            {selectedItem.ad_img?.length > 0 && (
              <div className="marketplace-detail-images">
                {selectedItem.ad_img.map((img, i) => (
                  <img key={i} src={getImageUrl(img)} alt="" className="marketplace-detail-img" />
                ))}
              </div>
            )}

            {/* Info */}
            <div className="marketplace-detail-info">
              <h2 className="marketplace-detail-title">{selectedItem.ad_title || 'Item'}</h2>
              {selectedItem.ad_amount && (
                <p className="marketplace-detail-price">Amount: {selectedItem.ad_amount}</p>
              )}
            </div>

            {/* Seller info */}
            <div className="marketplace-detail-section">
              <h3>Seller Information</h3>
              {selectedItem.ad_email && <p>Email: {selectedItem.ad_email}</p>}
              {selectedItem.ad_contact && <p>Contact: {selectedItem.ad_contact}</p>}
            </div>

            {/* Other info */}
            <div className="marketplace-detail-section">
              <h3>Other Information</h3>
              {selectedItem.ad_web_url && <p>Website: {selectedItem.ad_web_url}</p>}
              {selectedItem.ad_company && <p>Company: {selectedItem.ad_company}</p>}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Marketplace;
